mapper.select:

    /*
    1. ID: getUseTotal
    2. 업무명: 
    3. 업무설명:회원의 전체사용건수(환경 실청 건수)
    */
select count(*) from CRBN_QR_USE_HST    WHERE mbr_id = #{mbrId}


            /*
            1. ID: getMbrRanking
            2. 업무명: 
            3. 업무설명:회원의 사용건수의 랭킹
            */
			select  mbr_ranking from (
	            select mbr_id, cnt, RANK() OVER (ORDER BY cnt DESC) AS mbr_ranking
				from (
					select mbr_id, count(*) cnt
					from CRBN_QR_USE_HST
					group by mbr_id
				) a 
            ) b
            where mbr_id = #{mbrId}


/*
    1. ID: getStoreMemberCount
    2. 업무명: 
    3. 업무설명: 가맹점의 회원수
*/

select count(*) from CRBN_QR_USE_INFO where store_id = #{storeId}
